import { cn } from "@/lib/utils"

type CatalogIconProps = React.HTMLAttributes<SVGSVGElement> & {
  flairsize?: "sm" | "md" | "lg"
  iconClassName?: string
}

function createEmbeddedCatalogIcon(href: string) {
  return ({
    className,
    iconClassName,
    flairsize: _ignored,
    ...rest
  }: CatalogIconProps) => (
    <div className={className}>
      <svg
        viewBox="0 0 1 1"
        className={cn("size-full", iconClassName)}
        {...rest}
      >
        <image
          href={href}
          width="1"
          height="1"
          preserveAspectRatio="xMidYMid meet"
        />
      </svg>
    </div>
  )
}

